const ReportCard: React.FC<{ 
    definition: ReportDefinition, 
    reports: Report[], 
    onNavigate: (def: ReportDefinition) => void,
    onViewPending: (list: string[]) => void
}> = ({ definition, reports, onNavigate, onViewPending }) => {

    const stats = useMemo(() => {
        // For individual barangays, if there are no records, total is still 1 requirement
        const total = reports.length || 1; 
        const done = reports.filter(r => r.STATUS === 'Completed').length;
        const pending = total - done;
        const percentage = total > 0 ? Math.round((done / total) * 100) : 0;

        let latest = '';
        reports.forEach(r => {
            const dateStr = r['LAST UPDATED'];
            if (dateStr && dateStr !== 'Legacy Data' && (!latest || new Date(dateStr) > new Date(latest))) {
                latest = dateStr;
            }
        });

        return { total, done, pending, percentage, latest };
    }, [reports]);

    const isExtended = useMemo(() => {
        if (!definition.extensionUntil) return false;
        return new Date() <= new Date(definition.extensionUntil);
    }, [definition.extensionUntil]);

    const deadlineDateObj = useMemo(() => getNextDeadlineDate(definition), [definition]);
    const formattedDeadline = useMemo(() => {
        const options: Intl.DateTimeFormatOptions = { month: 'long', day: 'numeric' };
        return deadlineDateObj.toLocaleDateString('en-US', options);
    }, [deadlineDateObj]);

    const pendingList = useMemo(() => {
        if (reports.length === 0) return ['No current submission recorded'];

        const isBarangayLevel = definition.category === 'Barangay' || 
            ['FTJS', 'ASF (Barangay)', 'Kasambahay', 'BFDP', 'SKFPD', 'VAW-VAC Incidents', 'BARCO'].includes(definition.id);

        if (isBarangayLevel) {
            const uniqueCities = Array.from(new Set(reports.map(r => r.details?.city).filter(Boolean)));
            const results: string[] = [];
            uniqueCities.forEach(city => {
                const cityReports = reports.filter(r => r.details?.city === city);
                const total = cityReports.length;
                const completed = cityReports.filter(r => r.STATUS === 'Completed').length;
                if (completed < total) {
                    results.push(`${city} (${completed}/${total})`);
                }
            });
            return results.sort();
        } else {
            return reports.filter(r => r.STATUS !== 'Completed').map(r => r['LGU/BARANGAY']).sort();
        }
    }, [reports, definition.category, definition.id]);

    const getGradient = (category: string) => {
        if (category === 'Monthly') return 'from-blue-600 to-indigo-700';
        if (category === 'Quarterly') return 'from-orange-400 to-orange-600';
        if (category === 'Barangay') return 'from-indigo-600 to-purple-700';
        if (category === 'Weekly') return 'from-purple-500 to-pink-600';
        if (category === 'Quality Policy') return 'from-teal-500 to-emerald-700';
        if (category === 'Annual') return 'from-cyan-500 to-blue-700';
        return 'from-slate-600 to-slate-800';
    };

    const gradientClass = getGradient(definition.category);
    const isCompleted = stats.pending === 0 && reports.length > 0;

    return (
        <div 
            onClick={() => onNavigate(definition)}
            className={`
                relative p-6 rounded-[28px] transition-all duration-300 ease-out
                hover:-translate-y-2 hover:shadow-2xl cursor-pointer bg-gradient-to-br ${gradientClass}
                text-white flex flex-col h-full overflow-hidden border-t border-white/20
            `}
        >
            <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 2px, transparent 0)', backgroundSize: '16px 16px' }}></div>

            <div className="flex justify-between items-start mb-6">
                <div className="flex flex-col gap-2">
                    <span className="px-4 py-1.5 bg-white/20 backdrop-blur-md rounded-full text-[10px] font-black uppercase tracking-widest border border-white/10 w-fit">
                        {definition.category}
                    </span>
                    {isExtended && (
                        <span className="px-4 py-1.5 bg-amber-400 text-slate-900 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center w-fit animate-pulse">
                            <span className="mr-1">🕒</span> Extended
                        </span>
                    )}
                </div>
                <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black uppercase tracking-widest text-white/70 mb-1">Deadline</span>
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-white/20 backdrop-blur-md rounded-xl border border-white/10">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2-2v12a2 2 0 002 2z" />
                        </svg>
                        <span className="text-xs font-bold">{formattedDeadline}</span>
                    </div>
                </div>
            </div>

            <h3 className="text-2xl font-black mb-1 leading-tight drop-shadow-sm">
                {definition.title}
            </h3>
            <div className="flex items-center mb-6 opacity-80">
                <span className="text-[10px] font-bold uppercase tracking-widest mr-2">Last Updated:</span>
                <span className="text-[10px] font-black">{stats.latest || 'Never'}</span>
            </div>

            <div className="bg-white rounded-2xl p-5 mb-6 shadow-inner text-slate-800">
                <div className="flex justify-between items-center mb-4">
                    <div className="flex flex-col">
                        <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">Progress</span>
                        <div className="flex items-baseline">
                            <span className="text-2xl font-black">{stats.done}</span>
                            <span className="text-xs font-bold text-slate-400 ml-1">/ {stats.total}</span>
                        </div>
                    </div>
                    <div className="text-3xl font-black text-blue-600">
                        {stats.percentage}%
                    </div>
                    <div className="flex flex-col items-end gap-1">
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] font-bold text-slate-400 uppercase">Pending</span>
                            <span className="text-sm font-black text-amber-500">{stats.pending}</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] font-bold text-slate-400 uppercase">Done</span>
                            <span className="text-sm font-black text-emerald-500">{stats.done}</span>
                        </div>
                    </div>
                </div>

                <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden">
                    <div 
                        className="h-full bg-blue-600 rounded-full transition-all duration-1000 ease-out"
                        style={{ width: `${stats.percentage}%` }}
                    ></div>
                </div>
            </div>

            <div 
                className={`
                    mt-auto flex items-center justify-between px-5 py-4 rounded-2xl backdrop-blur-md transition-all
                    ${isCompleted ? 'bg-emerald-500/30 border border-emerald-400/30' : 'bg-slate-900/20 border border-white/10'}
                `}
                onClick={(e) => {
                    e.stopPropagation();
                    onViewPending(pendingList);
                }}
            >
                <div className="flex items-center gap-3">
                    <span className={`w-2 h-2 rounded-full ${isCompleted ? 'bg-emerald-400 animate-pulse' : 'bg-amber-400'}`}></span>
                    <span className="text-xs font-black uppercase tracking-widest">
                        {isCompleted ? 'Fully Compliant' : `Pending Updates`}
                    </span>
                </div>
                <svg className="w-4 h-4 text-white/60" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                </svg>
            </div>
        </div>
    );
};

