const GAS_API_URL: string = "https://script.google.com/macros/s/AKfycbxEMUgGz-DweApOvl6E4q96e7I0_Ko0YVQFVBRp6-UwhTv_VbleZ92FlMsJj2jRxi0/exec"; 

