    const completedTypesCount = REPORT_DEFINITIONS.reduce((acc, def) => {
        const typeReports = filteredReports.filter(r => r['REPORT TYPE'] === def.id);
        if (typeReports.length === 0) return acc;

        // A report type is "Fully Compliant" for the context if ALL its filtered records are 'Completed'
        const isFullyCompliant = typeReports.every(r => r.STATUS === 'Completed');
        return isFullyCompliant ? acc + 1 : acc;
    }, 0);

    return { 
        totalReports: total, 
        completedReports: completedTypesCount, 
        pendingReports: total - completedTypesCount, 
        contextName: barangayContext === 'All' ? userContext : `${barangayContext}, ${userContext}`
    };
  }, [filteredReports, userContext, barangayContext]);

  const handleNavigateToReport = (def: ReportDefinition) => { 
