                                className="w-full border-slate-200 p-4 pr-12 rounded-xl focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 bg-slate-50 text-sm font-bold shadow-sm transition-all outline-none"
                                required
                                autoFocus
                            />
                            <button 
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors"
                            >
                                {showPassword ? (
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                                    </svg>
                                ) : (
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" />
                                    </svg>
                                )}
                            </button>
                        </div>
                        {error && <p className="mt-2 text-xs text-red-600 font-bold">⚠️ {error}</p>}
                    </div>
                    <button type="submit" className="w-full py-4 bg-blue-600 text-white rounded-xl font-bold shadow-lg hover:bg-blue-700 transition-all">
                        Validate Password
                    </button>
                </form>
            )}

            {step === 3 && (
                <form onSubmit={handleBrgySubmit} className="space-y-5 animate-fade-in">
                    <div className="text-left">
                         <div className="flex justify-between items-end mb-2">
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Select Your Barangay</label>
                            <span className="text-[10px] text-emerald-600 font-bold bg-emerald-50 px-2 py-0.5 rounded-full">{selectedLgu} Verified</span>
                        </div>
                        <select
                            value={selectedBrgy}
                            onChange={(e) => setSelectedBrgy(e.target.value)}
                            className="w-full border-slate-200 p-4 rounded-xl focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 bg-slate-50 text-sm font-bold shadow-sm transition-all outline-none text-slate-700"
                            required
                        >
                            <option value="" disabled>Select Barangay...</option>
                            {availableBrgys.map((brgy) => <option key={brgy} value={brgy}>{brgy}</option>)}
                        </select>
                        <p className="mt-2 text-[10px] text-slate-400 font-medium italic">Available barangays are based on current database records.</p>
                    </div>
                    <button type="submit" disabled={!selectedBrgy} className="w-full py-4 bg-emerald-600 text-white rounded-xl font-bold shadow-lg hover:bg-emerald-700 transition-all">
                        Access Dashboard
                    </button>
                </form>
            )}

            <p className="mt-8 text-[10px] text-slate-300 font-medium">
                © 2025 DILG SAMAR | Nadem Ray Uy
            </p>
        </div>
      </div>
    </div>
  );
};

export default WelcomeModal;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Report, ReportDefinition } from './types';
import { fetchReports, updateReportData, importBatchData } from './services/dataService';
import { REPORT_DEFINITIONS, BARANGAY_LEVEL_REPORT_IDS } from './reportDefinitions'; 
import StatCard from './components/StatCard';
import { FtjsTable, BfdpTable, SkfpdTable, LguComplianceMatrix } from './components/ReportsTable';
import DynamicReportTable from './components/DynamicReportTable';
import EditReportModal from './components/EditReportModal';
import BatchImportModal from './components/BatchImportModal';
import SubmissionStatusView from './components/SubmissionStatusView';
import ChartView from './components/ChartView';
import WelcomeModal from './components/WelcomeModal';
import ExportMenu from './components/ExportMenu';
import ActionLogSheet from './components/ActionLogSheet';
import ComplianceChecklist from './components/ComplianceChecklist';
import ProvinceSummaryView from './components/ProvinceSummaryView';
import { ChartIcon, MaximizeIcon, ChartBarIcon, DownloadIcon, PlusIcon, CheckIcon } from './components/Icons';

declare const XLSX: any;

const LGU_LIST = [
  'ALMAGRO', 'BASEY', 'CALBIGA', 'CITY OF CALBAYOG', 'CITY OF CATBALOGAN (Capital)',
  'DARAM', 'GANDARA', 'HINABANGAN', 'JIABONG', 'MARABUT', 'MATUGUINAO', 'MOTIONG',
  'PAGSANGHAN', 'PARANAS', 'PINABACDAO', 'SAN JORGE', 'SAN JOSE DE BUAN',
  'SAN SEBASTIAN', 'SANTA MARGARITA', 'SANTA RITA', 'STO. NIÑO', 'TAGAPUL-AN',
  'TALALORA', 'TARANGNAN', 'VILLAREAL', 'ZUMARRAGA'
];

const App: React.FC = () => {
  const [userContext, setUserContext] = useState<string | null>(null); // LGU
  const [barangayContext, setBarangayContext] = useState<string | null>(null); // Barangay
  const [allReports, setAllReports] = useState<Report[]>([]);
  const [filteredReports, setFilteredReports] = useState<Report[]>([]);
  const [activeTab, setActiveTab] = useState("Monitoring Dashboard");
  const [activeSubTab, setActiveSubTab] = useState<string>(""); 
  const [statusFilter, setStatusFilter] = useState<string>("All");
  const [dashboardView, setDashboardView] = useState<'matrix' | 'submission' | 'chart'>('submission');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [editingReport, setEditingReport] = useState<Report | null>(null);

  const tabs = useMemo(() => {
    const baseTabs = ["Monitoring Dashboard", "Compliance Checklist", "Action Logsheet"];
    if (userContext === 'Province') {
      return [...baseTabs, "Submission Tally"];
    }
    return baseTabs;
  }, [userContext]);

  // Derived map of LGUs to their unique list of Barangays from fetched data
  const barangaysMap = useMemo(() => {
    const map: Record<string, Set<string>> = {};
    allReports.forEach(r => {
        if (r.details?.city && r.details?.barangay) {
            const city = r.details.city.toUpperCase();
            if (!map[city]) map[city] = new Set();
            map[city].add(r.details.barangay);
        }
    });
    const finalMap: Record<string, string[]> = {};
    Object.keys(map).forEach(city => {
        finalMap[city] = Array.from(map[city]).sort();
    });
    return finalMap;
  }, [allReports]);

  const activeReportDef = useMemo(() => REPORT_DEFINITIONS.find(d => d.id === activeSubTab), [activeSubTab]);

  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const reports = await fetchReports();
      setAllReports(reports);
    } catch (err: any) {
      setError(err instanceof Error ? err.message : String(err));
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const handleUserSelection = (lgu: string, brgy: string) => {
      setUserContext(lgu);
      setBarangayContext(brgy);
      if (lgu === 'Province') {
          setDashboardView('matrix');
          setActiveTab("Monitoring Dashboard");
      } else {
          setDashboardView('submission');
          setActiveTab("Monitoring Dashboard");
      }
  };

  const handleLogout = () => {
      setUserContext(null);
      setBarangayContext(null);
      setActiveSubTab("");
      setStatusFilter("All");
      // Optional: window.location.reload() can be used but state reset is smoother
  };

  useEffect(() => {
    if (!userContext) return;

    let reports = allReports;

    // Security Filtering: If not Province, only show reports for their specific LGU + Barangay
    if (userContext !== 'Province') {
        reports = reports.filter(r => 
            (r.details?.city === userContext) && 
            (barangayContext === 'All' || r.details?.barangay === barangayContext)
        );
    }

    if (activeSubTab && activeTab === "Monitoring Dashboard") {
        reports = reports.filter(r => r['REPORT TYPE'] === activeSubTab);
    }

    setFilteredReports(reports);
  }, [allReports, userContext, barangayContext, activeTab, activeSubTab]);

  const stats = useMemo(() => {
    const total = REPORT_DEFINITIONS.length;

    // Determine compliance at the report type level based on context
    const completedTypesCount = REPORT_DEFINITIONS.reduce((acc, def) => {
        const typeReports = filteredReports.filter(r => r['REPORT TYPE'] === def.id);
        if (typeReports.length === 0) return acc;

        // A report type is "Fully Compliant" for the context if ALL its filtered records are 'Completed'
        const isFullyCompliant = typeReports.every(r => r.STATUS === 'Completed');
        return isFullyCompliant ? acc + 1 : acc;
    }, 0);

    return { 
        totalReports: total, 
        completedReports: completedTypesCount, 
        pendingReports: total - completedTypesCount, 
        contextName: barangayContext === 'All' ? userContext : `${barangayContext}, ${userContext}`
    };
  }, [filteredReports, userContext, barangayContext]);

  const handleNavigateToReport = (def: ReportDefinition) => { 
    setActiveSubTab(def.id); 
    setActiveTab("Monitoring Dashboard");
  };

  const handleBackToDashboard = () => setActiveSubTab("");

  const handleSaveReport = async (updatedDetails: any) => {
    if (!editingReport) return;
    setLoading(true);
    try {
        const idKey = updatedDetails.project || editingReport['LGU/BARANGAY'];
        await updateReportData(editingReport['REPORT TYPE'], idKey, updatedDetails);
        await loadData();
        setEditingReport(null);
    } catch (err: any) { 
        alert("Save failed: " + (err instanceof Error ? err.message : String(err))); 
    } finally { 
        setLoading(false); 
    }
  };

  // Matrix calculation for Province view
  const lguMatrixData = useMemo(() => {
      if (userContext !== 'Province') return [];
      return LGU_LIST.map(lgu => {
          const rowData: any = { lgu };
          let compCount = 0;
          REPORT_DEFINITIONS.forEach(def => {
              const lguReports = allReports.filter(r => (r.details?.city === lgu) && r['REPORT TYPE'] === def.id);
              const totalBrgys = Array.from(new Set(allReports.filter(r => r.details?.city === lgu).map(r => r.details?.barangay))).length || 1;
              const completedBrgys = lguReports.filter(r => r.STATUS === 'Completed').length;

              rowData[def.id] = { 
                  status: completedBrgys === totalBrgys ? 'Completed' : completedBrgys > 0 ? 'Partial' : 'Pending',
                  date: `${completedBrgys}/${totalBrgys}`
              };
              if (completedBrgys === totalBrgys) compCount++;
          });
          rowData.completionRate = Math.round((compCount / REPORT_DEFINITIONS.length) * 100);
          rowData.completedCount = compCount; 
          return rowData;
      });
  }, [allReports, userContext]);

  const handleStatCardClick = (filter: string) => {
      if (activeSubTab) setActiveSubTab(""); // Return to overview if in a sub-tab
      setDashboardView('submission'); // Switch to card view to see filtered list
      setStatusFilter(filter);
  };

  return (
    <div className="bg-slate-50 min-h-screen font-sans text-slate-900 selection:bg-blue-100 flex flex-col">
      {!userContext && <WelcomeModal lgus={LGU_LIST} barangaysMap={barangaysMap} onSelect={handleUserSelection} />}

      {loading && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm">
            <div className="bg-white p-8 rounded-2xl shadow-2xl flex flex-col items-center border animate-fade-in-up">
                <div className="relative mb-6">
                    <div className="w-16 h-16 border-4 border-blue-100 rounded-full"></div>
                    <div className="w-16 h-16 border-4 border-blue-600 rounded-full animate-spin absolute top-0 left-0 border-t-transparent"></div>
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-2">Syncing Data...</h3>
                <p className="text-xs text-slate-500">Connecting to Barangay Records database</p>
            </div>
        </div>
      )}

      {userContext && (
        <div className="mx-auto p-4 md:p-8 w-full max-w-7xl flex-1 flex flex-col">
          <header className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white/80 backdrop-blur-md p-6 rounded-3xl shadow-sm border sticky top-4 z-30">
            <div className="flex items-center gap-4">
                <div className="bg-white p-2 rounded-xl border shadow-inner">
                    <img src="https://upload.wikimedia.org/wikipedia/commons/c/c9/Department_of_the_Interior_and_Local_Government_%28DILG%29_Seal_-_Logo.svg" alt="DILG" className="h-10" />
                </div>
                <div>
                    <h1 className="text-xl md:text-2xl font-black text-slate-800 tracking-tighter">DILG <span className="text-blue-600">SPARK</span></h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none mt-1">Samar Barangay Monitoring</p>
                </div>
            </div>
            <div className="flex items-center gap-4">
                <div className="text-right">
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Authenticated as</div>
                    <div className="text-sm font-black text-slate-700">{barangayContext === 'All' ? userContext : `${barangayContext}, ${userContext}`}</div>
                </div>
                <button 
                  onClick={handleLogout} 
                  title="Logout"
                  className="p-2 hover:bg-red-50 text-slate-400 hover:text-red-500 rounded-xl transition-all border border-slate-100"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7" /></svg>
                </button>
            </div>
          </header>

          <nav className="flex flex-wrap gap-2 mb-8 bg-white/60 p-1.5 rounded-2xl shadow-sm border backdrop-blur-sm overflow-x-auto no-scrollbar">
            {tabs.map((item) => (
                <button key={item} onClick={() => { setActiveTab(item); setActiveSubTab(""); setStatusFilter("All"); }} className={`flex-1 py-2.5 px-6 text-xs font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${activeTab === item ? 'bg-slate-800 text-white shadow-lg' : 'text-slate-500 hover:bg-white hover:text-slate-800'}`}>
                  {item}
                </button>
            ))}
          </nav>

          <main className="animate-fade-in flex-1">
              {activeTab === "Monitoring Dashboard" && (
                  <>
                      {!activeSubTab ? (
                          <>
                              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                                  <StatCard title="Total Reports" value={stats.totalReports} subtitle="Requirements" color="bg-blue-600" onClick={() => handleStatCardClick('All')} />
                                  <StatCard title="Complied" value={stats.completedReports} subtitle="Full Submissions" color="bg-emerald-600" onClick={() => handleStatCardClick('Completed')} />
                                  <StatCard title="Pending" value={stats.pendingReports} subtitle="Action Items" color="bg-amber-500" onClick={() => handleStatCardClick('Pending')} />
                                  <StatCard title="Status" value={stats.completedReports === stats.totalReports ? 'EXCELLENT' : 'ONGOING'} subtitle="Performance" color="bg-slate-700" onClick={() => setDashboardView(dashboardView === 'matrix' ? 'submission' : 'matrix')} />
                              </div>

                              {statusFilter !== "All" && (
                                  <div className="mb-6 flex items-center justify-between bg-blue-50 border border-blue-100 p-4 rounded-2xl">
                                      <div className="flex items-center gap-3">
                                          <div className="bg-blue-600 text-white p-1.5 rounded-lg">
                                              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>
                                          </div>
                                          <p className="text-sm font-bold text-blue-800">Showing <span className="underline">{statusFilter}</span> reports only</p>
                                      </div>
                                      <button onClick={() => setStatusFilter("All")} className="text-xs font-black uppercase text-blue-600 hover:text-blue-800 bg-white px-3 py-1.5 rounded-lg border border-blue-100 shadow-sm transition-all">Clear Filter</button>
                                  </div>
                              )}

                              {userContext === 'Province' && (
                                  <div className="flex gap-2 mb-6 bg-white p-1.5 rounded-xl border w-fit">
                                      <button onClick={() => setDashboardView('matrix')} className={`px-4 py-2 text-xs font-black rounded-lg transition-all ${dashboardView === 'matrix' ? 'bg-slate-800 text-white' : 'text-slate-500'}`}>Matrix View</button>
                                      <button onClick={() => setDashboardView('submission')} className={`px-4 py-2 text-xs font-black rounded-lg transition-all ${dashboardView === 'submission' ? 'bg-slate-800 text-white' : 'text-slate-500'}`}>Card View</button>
                                  </div>
                              )}

                              {dashboardView === 'matrix' && userContext === 'Province' ? (
                                  <LguComplianceMatrix data={lguMatrixData} columns={REPORT_DEFINITIONS.map(d => d.id)} onFocus={(lgu) => setUserContext(lgu)} />
                              ) : (
                                  <SubmissionStatusView reports={filteredReports} categoryFilter="All" statusFilter={statusFilter} onNavigate={handleNavigateToReport} />
                              )}
                          </>
                      ) : (
                          <div className="animate-fade-in">
                              <div className="flex items-center justify-between mb-6">
                                  <button onClick={handleBackToDashboard} className="flex items-center text-slate-500 hover:text-blue-600 font-bold transition-all">
                                      <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                                      Back to Overview
                                  </button>
                                  <h3 className="text-xl font-black text-slate-800">{activeReportDef?.title}</h3>
                              </div>
                              <DynamicReportTable definition={activeReportDef!} reports={filteredReports} onEdit={setEditingReport} />
                          </div>
                      )}
                  </>
              )}

              {activeTab === "Compliance Checklist" && (
                  <ComplianceChecklist reports={filteredReports} currentLgu={barangayContext === 'All' ? userContext! : barangayContext!} onNavigate={handleNavigateToReport} />
              )}

              {activeTab === "Action Logsheet" && (
                  <ActionLogSheet reports={filteredReports} currentLgu={barangayContext === 'All' ? userContext! : `${barangayContext}, ${userContext}`} />
              )}

              {activeTab === "Submission Tally" && userContext === 'Province' && (
                  <ProvinceSummaryView reports={allReports} lgus={LGU_LIST} barangaysMap={barangaysMap} />
              )}
          </main>

          <footer className="mt-auto py-8 text-center border-t border-slate-100">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">
               © 2025 DILG SAMAR | Nadem Ray Uy
             </p>
          </footer>
        </div>
      )}

      {editingReport && <EditReportModal report={editingReport} onSave={handleSaveReport} onClose={() => setEditingReport(null)} />}
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Report, ReportDefinition } from '../types';
import { REPORT_DEFINITIONS, BARANGAY_LEVEL_REPORT_IDS } from '../reportDefinitions';
import ExportMenu from './ExportMenu';

declare const XLSX: any;

interface ProvinceSummaryViewProps {
  reports: Report[];
  lgus: string[];
  barangaysMap: Record<string, string[]>;
}

const ProvinceSummaryView: React.FC<ProvinceSummaryViewProps> = ({ reports, lgus, barangaysMap }) => {
  const [searchTerm, setSearchTerm] = useState("");

  const summaryData = useMemo(() => {
    return lgus.map(lgu => {
      const lguData: any = { lgu };

      REPORT_DEFINITIONS.forEach(def => {
        const isBarangayReport = BARANGAY_LEVEL_REPORT_IDS.includes(def.id);
        const lguReports = reports.filter(r => 
          r['REPORT TYPE'] === def.id && 
          (r.details?.city?.toUpperCase() === lgu.toUpperCase() || r['LGU/BARANGAY'].toUpperCase().includes(lgu.toUpperCase()))
        );

        if (isBarangayReport) {
          const totalBarangays = (barangaysMap[lgu] || []).length;
          const submittedCount = lguReports.filter(r => r.STATUS === 'Completed').length;
          lguData[def.id] = {
            tally: `${submittedCount}/${totalBarangays}`,
            isFull: submittedCount >= totalBarangays && totalBarangays > 0,
            submitted: submittedCount,
            total: totalBarangays
          };
        } else {
          const isSubmitted = lguReports.some(r => r.STATUS === 'Completed');
          lguData[def.id] = {
            tally: isSubmitted ? '1/1' : '0/1',
            isFull: isSubmitted,
            submitted: isSubmitted ? 1 : 0,
            total: 1
          };
        }
      });

      return lguData;
    });
  }, [reports, lgus, barangaysMap]);

  const filteredData = useMemo(() => {
    if (!searchTerm) return summaryData;
    const term = searchTerm.toLowerCase();
    return summaryData.filter(d => d.lgu.toLowerCase().includes(term));
  }, [summaryData, searchTerm]);

  const handleExportPdf = () => {
    if (!(window as any).jspdf) return;
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF('l', 'mm', 'a4');

    doc.setFontSize(16);
    doc.text("DILG SAMAR - PROVINCE SUBMISSION TALLY", 148.5, 15, { align: 'center' });

    const headers = [['LGU Unit', ...REPORT_DEFINITIONS.map(d => d.id)]];
    const body = filteredData.map(row => [
      row.lgu,
      ...REPORT_DEFINITIONS.map(def => row[def.id].tally)
    ]);

    (doc as any).autoTable({
      head: headers,
      body: body,
      startY: 25,
      styles: { fontSize: 6, cellPadding: 1 },
      headStyles: { fillColor: [15, 23, 42], textColor: 255 },
      theme: 'grid'
    });

    doc.save(`Province_Submission_Tally.pdf`);
  };

  const handleExportExcel = () => {
    if (typeof XLSX === 'undefined') return;
    const headers = ['LGU Unit', ...REPORT_DEFINITIONS.map(d => d.id)];
    const body = filteredData.map(row => [
      row.lgu,
      ...REPORT_DEFINITIONS.map(def => row[def.id].tally)
    ]);

    const ws = XLSX.utils.aoa_to_sheet([headers, ...body]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Tally");
    XLSX.writeFile(wb, `Province_Submission_Tally.xlsx`);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col md:flex-row justify-between items-center gap-4">
        <div>
          <h3 className="text-xl font-black text-slate-800">Submission Tally Summary</h3>
          <p className="text-sm text-slate-500 font-medium">Overview of report submissions across all LGUs and Barangays.</p>
        </div>
        <div className="flex gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <input 
              type="text" 
              placeholder="Filter LGU..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-4 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>
          <ExportMenu onExportPdf={handleExportPdf} onExportExcel={handleExportExcel} label="Export Tally" />
        </div>
      </div>

      <div className="overflow-x-auto bg-white rounded-3xl border border-slate-200 shadow-xl relative custom-scrollbar">
        <table className="min-w-full divide-y divide-slate-100 border-separate border-spacing-0">
          <thead className="bg-slate-900 text-white">
            <tr>
              <th className="px-6 py-5 text-left text-[10px] font-black uppercase tracking-widest sticky left-0 bg-slate-900 z-30 border-r border-slate-800">
                LGU Unit
              </th>
              {REPORT_DEFINITIONS.map(def => (
                <th key={def.id} className="px-4 py-5 text-center text-[9px] font-black uppercase tracking-tighter truncate max-w-[100px]" title={def.title}>
                  {def.id}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredData.map((row, i) => (
              <tr key={i} className="hover:bg-slate-50 transition-colors group">
                <td className="px-6 py-4 text-sm font-extrabold text-slate-800 sticky left-0 bg-white z-20 border-r border-slate-100 group-hover:bg-slate-50 group-hover:text-blue-600">
                  {row.lgu}
                </td>
                {REPORT_DEFINITIONS.map(def => {
                  const data = row[def.id];
                  return (
                    <td key={def.id} className={`px-4 py-4 text-center border-r border-slate-50 last:border-0`}>
                      <div className="flex flex-col items-center">
                        <span className={`text-[11px] font-black tabular-nums ${data.isFull ? 'text-emerald-600' : data.submitted > 0 ? 'text-amber-600' : 'text-slate-300'}`}>
