                        </span>
                        <div className="w-12 bg-slate-100 h-1 rounded-full mt-1.5 overflow-hidden">
                          <div 
                            className={`h-full ${data.isFull ? 'bg-emerald-500' : 'bg-amber-400'}`} 
                            style={{ width: `${Math.min(100, (data.submitted / (data.total || 1)) * 100)}%` }} 
                          />
                        </div>
                      </div>
                    </td>
                  );
                })}
              </tr>
