              <span className="w-3 h-3 rounded-full bg-emerald-500"></span>
              <span className="text-sm font-bold text-slate-700">Full Compliance (All required items submitted)</span>
            </div>
            <div className="flex items-center gap-3">
              <span className="w-3 h-3 rounded-full bg-amber-400"></span>
              <span className="text-sm font-bold text-slate-700">Partial Compliance (Some items submitted)</span>
