        <div className="bg-slate-900 p-6 rounded-3xl text-white shadow-xl flex flex-col justify-center">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Quick Note</p>
          <p className="text-sm font-medium leading-relaxed italic opacity-80">
            "The Submission Tally provides a bird's eye view of all reporting units. For Barangay-level reports, the count represents the number of barangays in that LGU that have completed their submission."
          </p>
        </div>
      </div>
    </div>
  );
};

export default ProvinceSummaryView;

import React, { useMemo, useState } from 'react';
import { Report, ReportDefinition } from '../types';
import { REPORT_DEFINITIONS, BARANGAY_LEVEL_REPORT_IDS } from '../reportDefinitions';
import ExportMenu from './ExportMenu';

declare const XLSX: any;

interface ProvinceSummaryViewProps {
  reports: Report[];
  lgus: string[];
  barangaysMap: Record<string, string[]>;
}

const ProvinceSummaryView: React.FC<ProvinceSummaryViewProps> = ({ reports, lgus, barangaysMap }) => {
  const [selectedLgu, setSelectedLgu] = useState<string>(lgus[0] || "");
  const [searchTerm, setSearchTerm] = useState("");

  const currentBarangays = useMemo(() => {
    return barangaysMap[selectedLgu] || [];
  }, [selectedLgu, barangaysMap]);

  const tallyData = useMemo(() => {
    if (!selectedLgu) return [];

    return currentBarangays.map(brgy => {
      const row: any = { barangay: brgy };

      REPORT_DEFINITIONS.forEach(def => {
        const report = reports.find(r => 
          r['REPORT TYPE'] === def.id && 
          r.details?.city?.toUpperCase() === selectedLgu.toUpperCase() &&
          r.details?.barangay?.toUpperCase() === brgy.toUpperCase()
        );

        row[def.id] = {
          status: report ? report.STATUS : 'Pending',
          updated: report ? report['LAST UPDATED'] : 'Never',
          summary: report ? report['DATA SUMMARY'] : 'No data'
        };
      });

      return row;
    });
  }, [reports, selectedLgu, currentBarangays]);

  const filteredData = useMemo(() => {
    if (!searchTerm) return tallyData;
    const term = searchTerm.toLowerCase();
    return tallyData.filter(d => d.barangay.toLowerCase().includes(term));
  }, [tallyData, searchTerm]);

  const handleExportPdf = () => {
    if (!(window as any).jspdf) return;
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF('l', 'mm', 'a4');

    doc.setFontSize(16);
    doc.setTextColor(30, 41, 59);
    doc.text(`SUBMISSION TALLY: ${selectedLgu}`, 148.5, 15, { align: 'center' });

    doc.setFontSize(10);
    doc.text(`Generated on ${new Date().toLocaleString()}`, 148.5, 22, { align: 'center' });

    const headers = [['Barangay', ...REPORT_DEFINITIONS.map(d => d.id)]];
    const body = filteredData.map(row => [
      row.barangay,
      ...REPORT_DEFINITIONS.map(def => row[def.id].status)
    ]);

    (doc as any).autoTable({
      head: headers,
      body: body,
      startY: 30,
      styles: { fontSize: 6, cellPadding: 1.5 },
      headStyles: { fillColor: [15, 23, 42], textColor: 255 },
      columnStyles: {
        0: { fontStyle: 'bold', fillColor: [248, 250, 252] }
      },
      theme: 'grid'
    });

    doc.save(`Tally_${selectedLgu.replace(/\s+/g, '_')}.pdf`);
  };

  const handleExportExcel = () => {
    if (typeof XLSX === 'undefined') return;
    const headers = ['Barangay', ...REPORT_DEFINITIONS.map(d => d.id)];
    const body = filteredData.map(row => [
      row.barangay,
      ...REPORT_DEFINITIONS.map(def => row[def.id].status)
    ]);

    const ws = XLSX.utils.aoa_to_sheet([headers, ...body]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Barangay Tally");
    XLSX.writeFile(wb, `Tally_${selectedLgu.replace(/\s+/g, '_')}.xlsx`);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col md:flex-row justify-between items-end gap-6">
        <div className="w-full md:w-1/3">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Select LGU Unit</label>
          <select 
            value={selectedLgu}
            onChange={(e) => setSelectedLgu(e.target.value)}
            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold shadow-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          >
            {lgus.map(lgu => (
              <option key={lgu} value={lgu}>{lgu}</option>
            ))}
          </select>
        </div>

        <div className="flex-1 flex gap-4 w-full md:w-auto">
          <div className="relative flex-1">
             <input 
              type="text" 
              placeholder="Filter Barangay..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-4 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>
          <ExportMenu onExportPdf={handleExportPdf} onExportExcel={handleExportExcel} label="Export LGU Tally" />
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="min-w-full divide-y divide-slate-100 border-separate border-spacing-0">
            <thead className="bg-slate-900 text-white">
              <tr>
                <th className="px-6 py-5 text-left text-[10px] font-black uppercase tracking-widest sticky left-0 bg-slate-900 z-30 border-r border-slate-800">
                  Barangay
                </th>
                {REPORT_DEFINITIONS.map(def => (
                  <th key={def.id} className="px-4 py-5 text-center text-[9px] font-black uppercase tracking-tighter truncate max-w-[120px] whitespace-nowrap" title={def.title}>
                    {def.id}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredData.length === 0 ? (
                <tr>
                  <td colSpan={REPORT_DEFINITIONS.length + 1} className="px-6 py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                    No records found for the selected LGU
                  </td>
                </tr>
              ) : (
                filteredData.map((row, i) => (
                  <tr key={i} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4 text-xs font-black text-slate-700 sticky left-0 bg-white z-20 border-r border-slate-100 group-hover:bg-slate-50">
                      {row.barangay}
                    </td>
                    {REPORT_DEFINITIONS.map(def => {
                      const data = row[def.id];
                      const isCompleted = data.status === 'Completed';
                      return (
                        <td key={def.id} className="px-4 py-4 text-center border-r border-slate-50 last:border-0">
                          <div className="flex flex-col items-center group/cell relative">
                            <span className={`w-3 h-3 rounded-full shadow-sm ${isCompleted ? 'bg-emerald-500 ring-4 ring-emerald-500/10' : 'bg-slate-200 opacity-60'}`}></span>
                            <span className={`mt-2 text-[8px] font-black uppercase tracking-tighter ${isCompleted ? 'text-emerald-600' : 'text-slate-300'}`}>
                              {isCompleted ? 'Done' : 'Pending'}
                            </span>

                            {/* Tooltip on hover */}
                            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 bg-slate-800 text-white p-3 rounded-xl shadow-2xl z-50 opacity-0 group-hover/cell:opacity-100 transition-opacity pointer-events-none text-left">
                               <p className="text-[10px] font-black border-b border-white/10 pb-1 mb-1">{def.title}</p>
                               <p className="text-[9px] font-medium opacity-80 leading-relaxed truncate">{data.summary}</p>
                               <p className="text-[8px] font-black text-slate-400 mt-2">UPDATED: {data.updated}</p>
                            </div>
                          </div>
                        </td>
                      );
                    })}
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-8">
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Color Guide</h4>
          <div className="space-y-3">
            <div className="flex items-center gap-3">
              <span className="w-3 h-3 rounded-full bg-emerald-500"></span>
              <span className="text-sm font-bold text-slate-700">Submitted (Completed)</span>
            </div>
            <div className="flex items-center gap-3">
              <span className="w-3 h-3 rounded-full bg-slate-200"></span>
              <span className="text-sm font-bold text-slate-700">Not Yet Submitted (Pending)</span>
            </div>
          </div>
        </div>
        <div className="bg-slate-900 p-6 rounded-3xl text-white shadow-xl flex flex-col justify-center">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Information</p>
          <p className="text-sm font-medium leading-relaxed italic opacity-80">
            "This table shows the real-time status of all required reports for each barangay in {selectedLgu}. Hover over any status indicator to see a snippet of the submitted data summary."
          </p>
        </div>
      </div>
    </div>
  );
};

export default ProvinceSummaryView;

import React, { useState, useMemo } from 'react';
import { Report, ReportDefinition } from '../types';
import { CheckIcon, DownloadIcon } from './Icons';
import ReportProgress from './ReportProgress';
import ExportMenu from './ExportMenu';
import { LGU_LIST } from '../services/dataService';

declare const XLSX: any;

interface DynamicReportTableProps {
  reports: Report[];
  definition: ReportDefinition;
  onEdit: (report: Report) => void;
  isProvince?: boolean;
}

const DynamicReportTable: React.FC<DynamicReportTableProps> = ({ reports, definition, onEdit, isProvince }) => {
  const [viewFiles, setViewFiles] = useState<{ title: string, urls: string[] } | null>(null);
  const [lguFilter, setLguFilter] = useState<string>("All");

  const displayedReports = useMemo(() => {
      if (!isProvince || lguFilter === "All") return reports;
      return reports.filter(r => {
          const city = (r.details?.city || "").toUpperCase();
          return city === lguFilter.toUpperCase();
      });
  }, [reports, lguFilter, isProvince]);

  const handleDownloadPdf = () => {
      if (!(window as any).jspdf) {
          alert("PDF generator not loaded.");
          return;
      }
      const { jsPDF } = (window as any).jspdf;
      const doc = new jsPDF('l', 'mm', 'a4');
      const dateStr = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
      doc.setFontSize(12).text("DILG-SAMAR", 148.5, 15, { align: 'center' });

      const filterSuffix = isProvince && lguFilter !== "All" ? ` - ${lguFilter}` : "";
      doc.setFontSize(11).text(`Full Data Export: ${definition.title}${filterSuffix} as of ${dateStr}`, 148.5, 22, { align: 'center' });

      const headers = ['LGU/BARANGAY', ...definition.fields.map(f => f.label), 'STATUS', 'LAST UPDATED'];
      const data = displayedReports.map(report => {
          const row = [report['LGU/BARANGAY']];
          definition.fields.forEach(field => {
              let val = report.details?.[field.key];
              if (Array.isArray(val)) val = `${val.length} file(s) attached`;
              else if (typeof val === 'string' && val.startsWith('data:')) val = 'File Pending Upload';
              row.push(val || '');
          });
          row.push(report.STATUS);
          row.push(report['LAST UPDATED']);
          return row;
      });
      (doc as any).autoTable({ head: [headers], body: data, startY: 30, styles: { fontSize: 6, cellPadding: 1 }, headStyles: { fillColor: [30, 41, 59], textColor: 255 }, theme: 'grid' });
      doc.save(`${definition.title}${filterSuffix.replace(/\s+/g, '_')}_Export.pdf`);
  };

  const handleDownloadExcel = () => {
      if (typeof XLSX === 'undefined') { alert("Excel library not loaded."); return; }
      const headers = ['LGU/BARANGAY', ...definition.fields.map(f => f.label), 'STATUS', 'LAST UPDATED'];
      const data = displayedReports.map(report => {
          const row = [report['LGU/BARANGAY']];
          definition.fields.forEach(field => {
              let val = report.details?.[field.key];
              if (Array.isArray(val)) val = val.join(', ');
              row.push(val || '');
          });
          row.push(report.STATUS);
          row.push(report['LAST UPDATED']);
          return row;
      });
      const ws = XLSX.utils.aoa_to_sheet([headers, ...data]);
      const wb = XLSX.utils.book_new();
      const filterSuffix = isProvince && lguFilter !== "All" ? `_${lguFilter}` : "";
      XLSX.utils.book_append_sheet(wb, ws, "Full Report Data");
      XLSX.writeFile(wb, `${definition.title}${filterSuffix.replace(/\s+/g, '_')}_Export.xlsx`);
  };

  if (reports.length === 0) {
    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex justify-end"><ExportMenu onExportPdf={() => {}} onExportExcel={() => {}} disabled /></div>
            <div className="bg-white p-12 rounded-2xl shadow-sm border border-slate-200 text-center text-slate-500">No reports match filters.</div>
        </div>
    );
  }

  const getHeaderStyle = () => {
    switch(definition.category) {
      case 'Monthly': return 'bg-gradient-to-r from-blue-700 to-blue-800';
      case 'Quarterly': return 'bg-gradient-to-r from-orange-600 to-orange-700';
      case 'Barangay': return 'bg-gradient-to-r from-indigo-600 to-indigo-800';
      default: return 'bg-gradient-to-r from-teal-700 to-teal-800';
    }
  };

  const getColumnClasses = (accessor: string) => {
      if (accessor === 'LGU/BARANGAY' || accessor === 'city' || accessor === 'barangay') return "w-[200px] min-w-[160px] text-slate-900 font-bold whitespace-normal align-top";
      return "min-w-[120px] whitespace-normal break-words text-slate-700 align-top";
  };

  return (
    <div className="space-y-6 animate-fade-in">
        <ReportProgress reports={displayedReports} category={definition.category} />

        <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white/50 p-4 rounded-2xl border border-slate-200">
            <div className="flex-1 w-full">
                {isProvince && (
                    <div className="flex items-center gap-3">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">Filter LGU Unit:</label>
                        <select 
                            value={lguFilter}
                            onChange={(e) => setLguFilter(e.target.value)}
                            className="bg-white border border-slate-200 rounded-xl px-4 py-2 text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500 transition-all min-w-[200px] shadow-sm"
                        >
                            <option value="All">All Samar LGUs</option>
                            {LGU_LIST.map(lgu => <option key={lgu} value={lgu}>{lgu}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="flex items-center gap-3">
                {definition.templateUrl && (
                    <a href={definition.templateUrl} target="_blank" rel="noreferrer" className="flex items-center px-5 py-2.5 bg-indigo-600 text-white rounded-lg text-sm font-bold shadow-md hover:bg-indigo-700 transition-all hover:-translate-y-0.5">
                        <svg className="w-4 h-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                        Download Template
                    </a>
                )}
                <ExportMenu onExportPdf={handleDownloadPdf} onExportExcel={handleDownloadExcel} label={lguFilter === 'All' ? "Export Full Data" : `Export ${lguFilter}`} />
            </div>
        </div>

        <div className="overflow-x-auto bg-white rounded-2xl shadow-md shadow-slate-200/50 border border-slate-200">
        <table className="min-w-full divide-y divide-slate-100 table-fixed">
            <thead className={getHeaderStyle()}>
            <tr>
                {definition.columns.map((col) => (
                <th key={col.accessor} className={`px-4 py-5 text-left text-xs font-bold text-white uppercase tracking-wider ${getColumnClasses(col.accessor)} !text-white align-bottom opacity-90`}>
                    {col.header}
                </th>
                ))}
                <th className="px-4 py-5 text-center text-xs font-bold text-white uppercase tracking-wider w-[120px] min-w-[100px] sticky right-0 z-10 !text-white align-bottom shadow-xl opacity-90" style={{backgroundColor: 'inherit'}}>Action</th>
            </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-100">
            {displayedReports.length === 0 ? (
                <tr>
                    <td colSpan={definition.columns.length + 1} className="px-4 py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                        No submissions found for the selected filter
                    </td>
                </tr>
            ) : (
                displayedReports.map((report, idx) => (
                    <tr key={idx} className={`transition-colors duration-150 ${report.STATUS === 'Completed' ? 'bg-emerald-50/40 hover:bg-emerald-50/70' : report.STATUS === 'Overdue' ? 'bg-red-50/30 hover:bg-red-50/60' : 'hover:bg-slate-50'}`}>
                    {definition.columns.map((col) => {
                        let val = (report as any)[col.accessor];
                        if (val === undefined && report.details) val = report.details[col.accessor];
                        return (
                        <td key={col.accessor} className={`px-4 py-4 text-sm ${getColumnClasses(col.accessor)}`}>
                            {col.type === 'link' && val ? (
                                (() => {
                                    const valStr = Array.isArray(val) ? val.join(',') : String(val);
                                    if (valStr.startsWith('data:')) return <div className="inline-flex items-center px-2 py-1 bg-amber-50 border border-amber-200 rounded text-[10px] text-amber-700 font-bold uppercase tracking-tighter"><span className="w-2 h-2 rounded-full bg-amber-400 mr-1.5 animate-pulse"></span>File Attached</div>;
                                    const links = valStr.split(/[\n,]+/).filter((v: string) => v.trim().startsWith('http'));
                                    if (links.length > 1) return <button onClick={() => setViewFiles({ title: report['LGU/BARANGAY'], urls: links })} className="inline-flex items-center justify-center text-blue-700 hover:text-white hover:bg-blue-600 bg-blue-50 border border-blue-200 px-3 py-1.5 rounded-lg transition-all text-xs font-bold shadow-sm w-full"><span className="mr-1.5 text-lg">📂</span> View {links.length} Files</button>;
                                    if (links.length === 1) return <a href={links[0].trim()} target="_blank" rel="noreferrer" className="inline-flex items-center text-blue-600 hover:text-blue-800 font-medium px-2 py-1 rounded hover:bg-blue-50 transition-colors"><span className="mr-1">📎</span> View</a>;
                                    return <span className="text-xs text-slate-400 italic font-medium">Pending Sync</span>;
                                })()
                            ) : col.type === 'badge' ? (
                            <StatusBadge status={report.STATUS} isOverdue={report.isOverdue} />
                            ) : (
                            <span>{val}</span>
                            )}
                        </td>
                        );
                    })}
                    <td className="px-4 py-4 whitespace-nowrap text-sm font-medium align-middle sticky right-0 bg-inherit border-l border-slate-100 text-center">
                        <button 
                            onClick={() => onEdit(report)} 
                            disabled={report.isLocked}
                            className={`px-3 py-1.5 rounded-md transition-colors text-[10px] uppercase font-bold shadow-sm border ${
                                report.isLocked 
                                ? 'bg-slate-50 text-slate-400 border-slate-200 cursor-not-allowed' 
                                : 'bg-white text-blue-600 hover:text-blue-900 border-blue-300 hover:bg-blue-50'
                            }`}
                        >
                            {report.isLocked ? 'LOCKED' : 'UPDATE'}
                        </button>
                    </td>
                    </tr>
                ))
            )}
            </tbody>
        </table>
        </div>

        {viewFiles && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/70 backdrop-blur-sm p-4 animate-fade-in">
                <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md max-h-[80vh] flex flex-col overflow-hidden border border-white/20 ring-1 ring-black/5">
                    <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50 backdrop-blur-sm">
                        <div>
                            <h3 className="font-bold text-slate-800 text-lg tracking-tight">Attached Files</h3>
                            <p className="text-xs text-slate-500 font-medium">{viewFiles.title}</p>
                        </div>
